#!/usr/bin/env python3\n# -*- coding: utf-8 -*-\n"""\n公众号历史文章 → RAG 知识库 转换脚本\n\n将 moat-site/src/content/articles/ 下的历史 markdown 文章，\n转换为结构化 RAG 知识库 JSON 格式，供持卡评判/公告点评/亮点挖掘等下游任务使用。\n\n输出格式：\n  - data/articles_kb.json        # RAG 知识库主文件（分块存，可直接建向量索引）\n  - data/articles_kb_index.json   # 文章级别索引（标题/日期/分类/标签）\n\n设计原则：\n  1. 兼容现有 common.schema.CreditCardItem 结构\n  2. 支持持卡评判（评分/ROI计算）、公告点评（消息+分析）、亮点挖掘（小众卡/权益发现）\n  3. 按 ## 小节切分 + 滑动窗口重叠，保证检索召回质量\n  4. 非信用卡内容（职场/读书/生活等）标记为 general 但保留，可选择性过滤\n\n用法：\n    python scripts/convert_articles_to_rag.py\n    python scripts/convert_articles_to_rag.py --output data/articles_kb.json\n    python scripts/convert_articles_to_rag.py --min-chars 300\n"""\n\nimport argparse\nimport json\nimport os\nimport re\nimport sys\nfrom datetime import datetime\n\n_HERE = os.path.dirname(os.path.abspath(__file__))\n_PROJECT_ROOT = os.path.dirname(_HERE)  # 项目根\nif _PROJECT_ROOT not in sys.path:\n    sys.path.insert(0, _PROJECT_ROOT)\n\n# ── 配置 ──────────────────────────────────────────────────\nARTICLES_DIR = r"D:\ckl\个人\bat\moat-site\src\content\articles"\nDEFAULT_OUTPUT = os.path.join(_PROJECT_ROOT, "data", "articles_kb.json")\nDEFAULT_INDEX = os.path.join(_PROJECT_ROOT, "data", "articles_kb_index.json")\n\n# 滑动窗口分块参数\nCHUNK_SIZE = 500      # 字符数\nCHUNK_OVERLAP = 100   # 重叠字符数\n\n# 银行名称关键词（用于从文章中识别涉及的银行）\nBANK_KEYWORDS = {\n    "工商银行": ["工行", "工商银行", "工银"],\n    "农业银行": ["农行", "农业银行"],\n    "中国银行": ["中行", "中国银行"],\n    "建设银行": ["建行", "建设银行"],\n    "交通银行": ["交行", "交通银行"],\n    "邮储银行": ["邮储", "邮政储蓄", "邮储银行", "邮储信用卡"],\n    "招商银行": ["招行", "招商", "招商银行"],\n    "中信银行": ["中信", "中信银行"],\n    "光大银行": ["光大", "光大银行"],\n    "华夏银行": ["华夏", "华夏银行"],\n    "民生银行": ["民生", "民生银行"],\n    "广发银行": ["广发", "广发银行", "废行"],\n    "平安银行": ["平安", "平安银行", "平安口袋"],\n    "浦发银行": ["浦发", "浦发银行", "浦大喜奔"],\n    "兴业银行": ["兴业", "兴业银行", "兴业生活"],\n    "恒丰银行": ["恒丰", "恒丰银行"],\n    "浙商银行": ["浙商", "浙商银行"],\n    "北京银行": ["北京银行", "掌上京彩"],\n    "上海银行": ["上海银行"],\n    "盛京银行": ["盛京", "盛京银行", "刷新生活"],\n    "天津银行": ["天津银行"],\n    "宁波银行": ["宁波银行"],\n    "富邦华一": ["富邦", "富邦华一"],\n}\n\n# 卡组织关键词\nCARD_ORG_KEYWORDS = {\n    "银联": ["银联", "云闪付", "UnionPay"],\n    "Visa": ["Visa", "visa", "VISA"],\n    "万事达": ["万事达", "MasterCard", "mastercard", "Master"],\n    "运通/AE": ["运通", "American Express", "AE", "百夫长", "Centurion"],\n    "JCB": ["JCB"],\n}\n\n# 分类关键词（用于自动标注文章类别）\nCATEGORY_KEYWORDS = {\n    "持卡评判": [\n        "评分", "打分", "推荐", "值得", "建议持有", "持卡建议",\n        "年费评分", "收益评分", "总分", "ROI", "回血",\n        "结余", "年省", "每年节省", "回血可备",\n    ],\n    "公告点评": [\n        "公告", "通知", "上线", "发布", "温暖", "升级",\n        "缩水", "调整", "变更", "下架", "新规",\n    ],\n    "亮点挖掘": [\n        "小众卡", "神卡", "入门好卡", "隐藏", "冷门",\n        "终免", "免年费", "返现", "活动", "羊毛",\n    ],\n    "周报资讯": [\n        "CW", "周报", "周记", "本周", "汇总",\n        "资讯", "信息三则", "快讯",\n    ],\n    "知识科普": [\n        "攻略", "教程", "怎么", "如何", "指南",\n        "操作路径", "兑换路径", "查询路径",\n    ],\n}\n\n# 非信用卡内容标记\nNON_CARD_TAG_PATTERNS = [\n    "读书", "职场", "生活", "工具", "AI", "亲子",\n    "碎碎念", "流水账", "推荐", "书单",\n]\n\n# ── 工具函数 ──────────────────────────────────────────────\n\n\ndef parse_frontmatter(text: str) -> dict:\n    """解析 YAML 格式 frontmatter。"""\n    meta = {"title": "", "date": "", "tags": [], "draft": False}\n    m = re.match(r"^---\s*\n(.*?)\n---", text, re.DOTALL)\n    if not m:\n        return meta\n    front = m.group(1)\n    for line in front.split("\n"):\n        line = line.strip()\n        if line.startswith("title:"):\n            meta["title"] = line[len("title:"):].strip().strip('"').strip("'")\n        elif line.startswith("date:"):\n            raw = line[len("date:"):].strip()\n            # 尝试解析多种日期格式\n            meta["date"] = raw\n        elif line.startswith("tags:"):\n            # tags: ["信用卡", "活动"]\n            tags_match = re.findall(r'"([^"]+)"', line)\n            if tags_match:\n                meta["tags"] = tags_match\n        elif line.startswith("draft:"):\n            meta["draft"] = "true" in line.lower()\n    return meta\n\n\ndef parse_date_from_filename(filename: str) -> str:\n    """从文件名提取日期：20210217-xxx.md → 2021-02-17"""\n    m = re.match(r"(\d{4})(\d{2})(\d{2})-", os.path.basename(filename))\n    if m:\n        return f"{m.group(1)}-{m.group(2)}-{m.group(3)}"\n    return ""\n\n\ndef strip_markdown(text: str) -> str:\n    """清理 markdown 格式，保留正文。"""\n    # 移除 frontmatter\n    text = re.sub(r"^---\s*\n.*?\n---", "", text, flags=re.DOTALL)\n    # 移除图片 ![...](...)\n    text = re.sub(r"!\[.*?\]\(.*?\)", "", text)\n    # 移除行内链接 [text](url) → text\n    text = re.sub(r"\[([^\]]*?)\]\(https?://[^\s\)]+\)", r"\1", text)\n    # 移除独立链接 (http...)\n    text = re.sub(r"\(https?://[^\s\)]+\)", "", text)\n    # 移除 > 块引用标记\n    text = re.sub(r"^>\s*", "", text, flags=re.MULTILINE)\n    # 移除加粗/斜体标记\n    text = re.sub(r"\*{1,3}([^*]+)\*{1,3}", r"\1", text)\n    # 清理空行（保留段落结构）\n    text = re.sub(r"\n{4,}", "\n\n", text)\n    return text.strip()\n\n\ndef extract_banks(text: str) -> list[str]:\n    """从正文中提取涉及的银行列表。"""\n    banks = set()\n    for bank, keywords in BANK_KEYWORDS.items():\n        for kw in keywords:\n            if kw in text:\n                banks.add(bank)\n                break\n    return sorted(banks, key=lambda b: -len(b))\n\n\ndef classify_article(title: str, text: str) -> list[str]:\n    """对文章进行分类，返回分类标签列表。"""\n    combined = f"{title}\n{text}"\n    categories = []\n    for cat, keywords in CATEGORY_KEYWORDS.items():\n        for kw in keywords:\n            if kw in combined:\n                categories.append(cat)\n                break\n    if not categories:\n        # 默认归类\n        categories.append("一般资讯")\n    return categories\n\n\ndef is_card_related(title: str, text: str, tags: list) -> bool:\n    """判断是否与信用卡相关。"""\n    # 如果有信用卡标签\n    if any("信用卡" in t or "卡" == t or "权益" in t for t in tags):\n        return True\n    # 如果标题或正文包含信用卡核心词\n    card_keywords = [\n        "信用卡", "信用", "银行卡", "年费", "积分", "刷卡",\n        "申卡", "办卡", "销卡", "持卡", "卡评分", "卡权益",\n        "返现", "里程", "贵宾厅", "银行", "小白金", "大白金",\n        "神卡", "小众卡", "入门卡", "联名卡",\n    ]\n    combined = f"{title} {text[:200]}"\n    for kw in card_keywords:\n        if kw in combined:\n            return True\n    # 非信用卡内容排除\n    non_card = ["读书笔记", "书单", "职场", "水浒", "亲子", "孩子",\n                "工具推荐", "AI", "OpenCLaw", "Claude"]\n    for kw in non_card:\n        if kw in title:\n            return False\n    return False\n\n\ndef extract_card_types(text: str) -> list[str]:\n    """提取文章中提到的卡类型/卡种名称。"""\n    card_types = []\n    # 常见卡种模式\n    patterns = [\n        r"(?:高端|顶级|大白金|小白金|白金|金卡|普卡|钻石|无限)",\n        r"(?:.*?联名)卡",\n        r"(?:标准|简约|经典)白金卡",\n        r"(?:精英|悠|标|标白|悠白|精英白)白",\n    ]\n    found = set()\n    for p in patterns:\n        for m in re.finditer(p, text):\n            # 往前找可能的卡名\n            start = max(0, m.start() - 20)\n            context = text[start:m.end()]\n            # 精简提取\n            card_name = m.group().strip()\n            if len(card_name) >= 2:\n                found.add(card_name)\n    card_types = sorted(found)\n    # 限定长度，避免杂音\n    return [c for c in card_types if len(c) <= 20]\n\n\ndef smart_chunk(text: str, chunk_size: int = CHUNK_SIZE,\n                overlap: int = CHUNK_OVERLAP) -> list[dict]:\n    """智能分块：优先按 ## 标题切分，超出部分滑动窗口。"""\n    # 按 ## 一级标题切分\n    sections = re.split(r"(?=^#{1,2}\s)", text, flags=re.MULTILINE)\n    chunks = []\n\n    for sec in sections:\n        sec = sec.strip()\n        if not sec or len(sec) < 20:\n            continue\n\n        # 提取章节标题\n        sec_title = ""\n        title_match = re.match(r"^#{1,2}\s+(.*)", sec)\n        if title_match:\n            sec_title = title_match.group(1).strip()\n            sec_body = sec[title_match.end():].strip()\n        else:\n            sec_body = sec\n\n        # 如果小节很短，直接作为一个 chunk\n        if len(sec) <= chunk_size:\n            chunks.append({\n                "section": sec_title,\n                "text": sec,\n                "char_count": len(sec),\n            })\n            continue\n\n        # 长的按段落进一步切分\n        paragraphs = re.split(r"\n\s*\n", sec_body)\n        current = sec_title + "\n" if sec_title else ""\n        current += paragraphs[0] if paragraphs else ""\n\n        for para in paragraphs[1:]:\n            para = para.strip()\n            if not para:\n                continue\n            if len(current) + len(para) <= chunk_size:\n                current += "\n\n" + para\n            else:\n                if current.strip():\n                    chunks.append({\n                        "section": sec_title,\n                        "text": current.strip(),\n                        "char_count": len(current),\n                    })\n                # 滑动重叠\n                overlap_text = current[-overlap:] if overlap < len(current) else current\n                current = overlap_text + "\n\n" + para\n\n        if current.strip():\n            chunks.append({\n                "section": sec_title,\n                "text": current.strip(),\n                "char_count": len(current),\n            })\n\n    # 如果什么都没分出来，整体作为一个 chunk\n    if not chunks and len(text.strip()) > 20:\n        chunks.append({\n            "section": "",\n            "text": text.strip(),\n            "char_count": len(text.strip()),\n        })\n\n    return chunks\n\n\n# ── 主流程 ──────────────────────────────────────────────────\n\n\ndef process_all_articles(articles_dir: str, min_chars: int = 200) -> tuple[list, list]:\n    """处理所有文章，返回知识库条目列表和索引列表。"""\n    kb_entries = []      # RAG 知识库条目（按 chunk 展开）\n    index_entries = []   # 文章级索引\n\n    if not os.path.isdir(articles_dir):\n        print(f"❌ 文章目录不存在: {articles_dir}")\n        return kb_entries, index_entries\n\n    files = sorted(os.listdir(articles_dir))\n    total = 0\n    card_count = 0\n    non_card_count = 0\n    skipped = 0\n\n    for fname in files:\n        if not fname.endswith(".md"):\n            continue\n\n        fpath = os.path.join(articles_dir, fname)\n        with open(fpath, "r", encoding="utf-8") as f:\n            raw = f.read()\n\n        # 跳过 draft 和太短的内容\n        meta = parse_frontmatter(raw)\n        if meta.get("draft", False):\n            skipped += 1\n            continue\n\n        title = meta.get("title", "") or fname.replace(".md", "")\n        date_str = meta.get("date", "") or parse_date_from_filename(fname)\n        tags = meta.get("tags", [])\n\n        # 清洗正文\n        clean_text = strip_markdown(raw)\n        if len(clean_text) < min_chars:\n            skipped += 1\n            continue\n\n        # 判断是否信用卡相关\n        card_related = is_card_related(title, clean_text, tags)\n        categories = classify_article(title, clean_text)\n        banks = extract_banks(clean_text)\n        card_types = extract_card_types(clean_text) if card_related else []\n\n        total += 1\n        if card_related:\n            card_count += 1\n        else:\n            non_card_count += 1\n\n        # 构建文章级索引\n        index_entry = {\n            "id": fname.replace(".md", ""),\n            "filename": fname,\n            "title": title,\n            "date": date_str,\n            "tags": tags,\n            "card_related": card_related,\n            "categories": categories,\n            "banks": banks,\n            "card_types": card_types,\n            "char_count": len(clean_text),\n            "chunk_count": 0,\n        }\n        index_entries.append(index_entry)\n\n        # 智能分块\n        chunks = smart_chunk(clean_text)\n\n        # 为每个 chunk 生成知识库条目\n        for i, chunk in enumerate(chunks):\n            chunk_text = chunk["text"]\n            if len(chunk_text) < 30:\n                continue\n\n            # 从 chunk 文本中再次识别银行（更精确）\n            chunk_banks = extract_banks(chunk_text)\n            if not chunk_banks:\n                chunk_banks = banks  # 回退到文章级\n\n            # 标签：分类 + 银行 + 是否有评分计算等\n            labels = list(categories)\n            if card_related:\n                labels.append("信用卡")\n            if any("评分" in chunk_text or "结余" in chunk_text or "收益" in chunk_text for _ in [1]):\n                labels.append("含定量计算")\n            if any("兑换路径" in chunk_text or "操作路径" in chunk_text for _ in [1]):\n                labels.append("操作指南")\n\n            entry = {\n                # ── RAG 检索字段 ──\n                "id": f"{fname.replace('.md', '')}_chunk{i:03d}",\n                "article_id": fname.replace(".md", ""),\n                "section": chunk["section"],\n                "text": chunk_text,\n                "char_count": len(chunk_text),\n\n                # ── 元数据字段 ──\n                "title": title,\n                "date": date_str,\n                "source": "历史公众号文章",\n                "filename": fname,\n\n                # ── 分类标签（用于过滤检索） ──\n                "card_related": card_related,\n                "categories": categories,\n                "labels": labels,\n\n                # ── 实体提取（银行/卡种） ──\n                "banks": chunk_banks,\n                "card_types": card_types if card_related else [],\n\n                # ── 兼容 CreditCardItem 结构 ──\n                "structured": {\n                    "类型": categories[0] if categories else "一般资讯",\n                    "涉及银行": chunk_banks,\n                    "是否信用卡相关": card_related,\n                },\n            }\n            kb_entries.append(entry)\n\n        index_entry["chunk_count"] = len([c for c in chunks if len(c["text"]) >= 30])\n        index_entry["kb_entry_count"] = sum(\n            1 for e in kb_entries if e["article_id"] == fname.replace(".md", "")\n        )\n\n    print(f"\n✅ 处理完成：")\n    print(f"   总文章数：{total}")\n    print(f"   信用卡相关：{card_count}")\n    print(f"   非信用卡：{non_card_count}")\n    print(f"   跳过（draft/过短）：{skipped}")\n    print(f"   知识库条目（chunk）：{len(kb_entries)}")\n    print(f"   分块比例：{len(kb_entries)/max(total,1):.1f} 块/篇")\n\n    return kb_entries, index_entries\n\n\ndef save_kb(kb_entries: list, index_entries: list,\n            kb_path: str, index_path: str):\n    """保存知识库和索引到 JSON 文件。"""\n    # 主知识库\n    kb_data = {\n        "generated_at": datetime.now().isoformat(timespec="seconds"),\n        "source": "历史公众号文章知识库",\n        "total_entries": len(kb_entries),\n        "total_articles": len(index_entries),\n        "chunk_size": CHUNK_SIZE,\n        "chunk_overlap": CHUNK_OVERLAP,\n        "usage": (\n            "RAG 检索说明：\n"\n            "  1. 使用 embedding 模型（如 bge-large-zh-v1.5）对 'text' 字段编码\n"\n            "  2. 检索时按 'card_related' / 'categories' / 'banks' 可做预过滤\n"\n            "  3. 检索结果按 'date' 降序 + cosine similarity 排序\n"\n            "  4. 召回后组装 LLM prompt 时，将 'title' + 'text' 作为上下文\n"\n            "  5. 持卡评判用 categories='持卡评判' 过滤；公告点评用 '公告点评'；亮点挖掘用 '亮点挖掘'"\n        ),\n        "entries": kb_entries,\n    }\n\n    os.makedirs(os.path.dirname(kb_path) or ".", exist_ok=True)\n    with open(kb_path, "w", encoding="utf-8") as f:\n        json.dump(kb_data, f, ensure_ascii=False, indent=2)\n    print(f"📝 知识库文件: {os.path.abspath(kb_path)}")\n\n    # 索引\n    index_data = {\n        "generated_at": datetime.now().isoformat(timespec="seconds"),\n        "total_articles": len(index_entries),\n        "card_related_count": sum(1 for e in index_entries if e["card_related"]),\n        "articles": index_entries,\n    }\n    with open(index_path, "w", encoding="utf-8") as f:\n        json.dump(index_data, f, ensure_ascii=False, indent=2)\n    print(f"📝 索引文件: {os.path.abspath(index_path)}")\n\n\ndef print_statistics(kb_entries: list, index_entries: list):\n    """打印知识库统计信息。"""\n    # 分类统计\n    cat_stats = {}\n    for e in kb_entries:\n        for c in e["categories"]:\n            cat_stats[c] = cat_stats.get(c, 0) + 1\n\n    print(f"\n📊 知识库分类统计：")\n    for cat, cnt in sorted(cat_stats.items(), key=lambda x: -x[1]):\n        print(f"   {cat}: {cnt} 块")\n\n    # 银行覆盖\n    bank_articles = {}\n    for e in index_entries:\n        if e["card_related"]:\n            for b in e["banks"]:\n                bank_articles.setdefault(b, 0)\n                bank_articles[b] += 1\n\n    if bank_articles:\n        print(f"\n🏦 银行覆盖（信用卡文章数）：")\n        for bk, cnt in sorted(bank_articles.items(), key=lambda x: -x[1])[:15]:\n            print(f"   {bk}: {cnt} 篇")\n\n    # 时间跨度\n    dates = [e["date"] for e in index_entries if e["date"]]\n    if dates:\n        print(f"\n📅 时间跨度：{min(dates)} ~ {max(dates)}")\n\n\ndef main():\n    parser = argparse.ArgumentParser(description="公众号历史文章 → RAG 知识库转换")\n    parser.add_argument("--articles-dir", default=ARTICLES_DIR,\n                        help="文章目录路径")\n    parser.add_argument("--output", default=DEFAULT_OUTPUT,\n                        help="知识库输出路径")\n    parser.add_argument("--index", default=DEFAULT_INDEX,\n                        help="索引输出路径")\n    parser.add_argument("--min-chars", type=int, default=200,\n                        help="最小文章字符数（低于此值跳过）")\n    parser.add_argument("--stats-only", action="store_true",\n                        help="仅统计，不生成知识库文件")\n    args = parser.parse_args()\n\n    kb_entries, index_entries = process_all_articles(\n        args.articles_dir, min_chars=args.min_chars\n    )\n\n    if not args.stats_only and kb_entries:\n        save_kb(kb_entries, index_entries, args.output, args.index)\n\n    print_statistics(kb_entries, index_entries)\n\n    # 输出简短示例\n    if kb_entries:\n        print(f"\n💡 检索示例——持卡评判相关 chunk（前 3 条）：")\n        card_judge = [e for e in kb_entries\n                      if "持卡评判" in e["categories"]][:3]\n        for e in card_judge:\n            print(f"   [{e['date']}] {e['title']} > {e['section'] or '全文'}")\n            print(f"   银行: {', '.join(e['banks'][:3]) or '未知'}")\n            print(f"   摘要: {e['text'][:100]}...")\n            print()\n\n\nif __name__ == "__main__":\n    main()\n